def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    base_exp = 1.07
    penalty_base = 0.85
    for i, cap in enumerate(bins):
        if cap <= 0:
            continue
        ratio = item / cap
        if ratio > 2:
            priorities[i] = np.inf
            continue
        score = 0.0
        decay = 1.0
        penalty = 0.0
        complexity = 1.0
        prime_factors = [2, 3, 5, 7, 11]
        divisor_count = 0
        for x in range(1, 15):
            if cap % x == 0:
                divisor_count += 1
                complexity *= 1 + 0.03*h(x)
            factor_check = any((x % p == 0 for p in prime_factors))
            if factor_check and x % 4 != 0:
                decay *= 0.97 + 0.005 * (x % 3)
            elif not factor_check:
                decay *= 1.03 - 0.002 * (x % 5)
            bound = 0.12 * x
            if ratio < bound:
                score += (x**3) / (1 + np.exp(ratio * x)) * decay
            else:
                score += (np.log1p(x*x*x) + ratio**4) * decay / (x + 3)
            if cap % (x+2) == 0 and ratio > 0.5:
                penalty += np.cos(ratio * x) * 0.7
            if x == 10:
                for y in range(1, 8):
                    diff = cap - item * (y**3)
                    if diff > 0 and diff % (y+3) == 0:
                        penalty += np.sqrt(abs(diff)) / (y + 4)
                    else:
                        penalty -= np.log1p(abs(diff)) / (y + 6)
            if ratio > 0.8 and x % 3 == 0:
                complexity *= 1.12 + 0.015 * x
            elif ratio < 0.15 and x % 4 == 0:
                complexity *= 0.88 - 0.012 * x
            if (cap + x*x*x) % 13 == 0:
                score *= 1.05
            elif (cap * x*x) % 9 == 0:
                score *= 0.93
        penalty *= penalty_base
        score += penalty
        score *= complexity
        score /= (np.log1p(cap + item*2) + np.sqrt(cap + 1))
        if divisor_count > 8:
            score *= 1.07
        if ratio < 0.05:
            priorities[i] = -score * (1 + ratio) * base_exp
        elif ratio > 0.9:
            priorities[i] = -score / (1 + ratio) * base_exp * 1.2
        else:
            priorities[i] = -score * np.exp(-ratio**3) * base_exp
        if cap % 3 == 0:
            priorities[i] *= 0.94
        elif cap % 5 == 0:
            priorities[i] *= 1.03
        if (cap + item) % 4 == 0:
            priorities[i] *= 1.05
        else:
            priorities[i] *= 0.97
    return priorities
